const item = $json;

// Solo bloqueamos si es TRASH absoluto o si ya fue rechazado por Guard
if (item.category === 'trash' || item.trash === true) return [];

let score = 0;
// Scoring dinámico para el feed
if (item.category === 'evento') score += 50;
if (item.category === 'plaza') score += 20;
if (item.city && item.city !== 'Global') score += 15;
if ((item.text_es || '').length > 200) score += 10;

return [{ json: { ...item, final_score: score } }];

const item = $input.first()?.json || {};
function escapeHTML(text) { return String(text||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const langs = [
  { code: 'ES', tg: '-5283488138', title: item.title_es || 'Nuevo Lead', text: item.text_es || item.texto_limpio, tag: 'Remitente' }
];

const results = [];
for (const l of langs) {
  function formatOutputContact(val, mode) {
    if (!val || val === 'Desconocido' || val === 'No disponible') return 'No disponible';
    if (String(val).startsWith('tg_id_')) {
      const id = val.replace('tg_id_', '');
      return mode === 'html' ? `<a href="tg://user?id=${id}">Chat Directo</a>` : `ID: ${id}`;
    }
    if (/[a-zA-Z]/.test(val) && !/\d/.test(val)) {
       const user = String(val).replace('@', '');
       return mode === 'html' ? `<a href="https://t.me/${user}">@${user}</a>` : `@${user}`;
    }
    const s = String(val).replace(/[^0-9]/g, '');
    return s.length >= 7 ? `+${s}` : val;
  }

  const tgContact = formatOutputContact(item.contact || item.final_contact, 'html');

  const categoryStr = (item.category === 'plaza') ? 'Plazas' : 'Eventos';

  const tgText = `<b>${escapeHTML(l.title)}</b>\n🏷️ <b>${categoryStr}</b>\n📍 <b>${escapeHTML(item.city || 'Desconocida')}</b>\n💰 <b>${escapeHTML(item.budget || 'Negociable')}</b>\n\n${escapeHTML(l.text || 'Sin texto')}\n\n👤 <b>${l.tag}:</b> ${tgContact}\n🔌 <b>Fuente:</b> ${escapeHTML(item.platform || 'WhatsApp')}`;

  results.push({
    json: { ...item, route_lang: l.code, tg_chat: l.tg, tg_text: tgText }
  });
}
return results;

// DYNAMIC ROUTING ENGINE v5.7 (STRICT MATCHING)
let leadData = {};
try { leadData = $node["Parse JSON1"].json; } catch(e) { return []; }
const category = String(leadData.category || 'evento').toLowerCase();
const cityDetected = String(leadData.city || 'global').toLowerCase();
const text = String(leadData.text_es || '').toLowerCase();

const routingTable = {
  "madrid": {
    keywords: ["madrid", "barajas", "serrano", "pozuelo"],
    targets: [
      { to: "34664266926@s.whatsapp.net", label: "MADRID" },
      { to: "34603346859@s.whatsapp.net", label: "MADRID" }
    ]
  },
  "ibiza": {
    keywords: ["ibiza", "eivissa", "mansour", "pacha", "lio", "ushuaia", "sant antoni"],
    targets: [
      { to: "34662058447@s.whatsapp.net", label: "IBIZA" },
      { to: "34642107796@s.whatsapp.net", label: "IBIZA" }
    ]
  },
  "london": {
    keywords: ["london", "londres", "mayfair", "soho", "chelsea"],
    targets: [
      { to: "120363425790792660@g.us", label: "LONDON" }
    ]
  },
  "miami": {
    keywords: ["miami", "south beach", "brickell", "miami beach"],
    targets: [
      { to: "17862812324@s.whatsapp.net", label: "MIAMI" },
      { to: "525532110621@s.whatsapp.net", label: "MIAMI" }
    ]
  },
  "paris": {
    keywords: ["paris", "francia", "france", "champs"],
    targets: [
      { to: "33744156314@s.whatsapp.net", label: "PARIS" }
    ]
  },
  "monaco": {
    keywords: ["monaco", "viena", "vienna", "monte carlo"],
    targets: [
      { to: "120363425790792660@g.us", label: "GLOBAL" }
    ]
  }
};

let matchedTargets = [];

// 1. PRIORITY: Explicit City Match (from IA detection)
if (routingTable[cityDetected]) {
    matchedTargets = [...routingTable[cityDetected].targets];
}

// 2. SECONDARY: Keyword Match (only if no explicit city match)
if (matchedTargets.length === 0) {
    for (const [key, config] of Object.entries(routingTable)) {
        if (config.keywords.some(kw => text.includes(kw))) {
             matchedTargets = [...matchedTargets, ...config.targets];
        }
    }
}

// 3. FALLBACK: Global feed
if (matchedTargets.length === 0 && (category === 'evento' || category === 'plaza')) {
  matchedTargets.push({ to: "120363425790792660@g.us", label: "GLOBAL" });
}

// Ensure unique targets
const uniqueTargets = Array.from(new Set(matchedTargets.map(t => t.to)))
  .map(to => matchedTargets.find(t => t.to === to));

if (uniqueTargets.length === 0) return [];

return uniqueTargets.map(t => ({
  json: { 
    ...leadData, 
    target_wa: t.to, 
    city_label: t.label 
  }
}));

const input = $input.first().json;
const item = input.message || input.body || input;
const textBody = item.text || item.caption || item.message?.text || '';

function findContact(obj) {
  if (!obj || typeof obj !== 'object') return null;
  const contact = obj.contact || obj.sender_contact || obj.from || obj.sender?.wa_id || '';
  if (typeof contact === 'string') {
    if (contact.includes('t.me/')) return contact.split('t.me/')[1];
    if (contact.startsWith('tg_id_')) return contact;
    if (contact.startsWith('@')) return contact;
    if (/^\d{7,15}$/.test(contact)) return 'tg_id_' + contact;
  }
  return null;
}

let sc = findContact(item) || findContact(input);
if (sc && !sc.startsWith('tg_id_')) {
  sc = sc.trim();
  if (!sc.startsWith('@')) sc = '@' + sc;
}

const sourceChatId = item.chatId || item.chat?.id || input.source_chat_id || '';

return [{ json: {
  ...item,
  platform: 'Telegram',
  sender_contact: sc || 'No_Username',
  final_contact: sc || 'No_Username',
  source_chat_id: sourceChatId,
  texto_limpio: textBody.trim(),
  looksValuable: textBody.length > 5
}}];

const input = $input.first().json;
const item = input.message || (input.messages && input.messages[0]) || input.body || input;
const textBody = item.text?.body || item.text || item.caption || item.body || '';

function getPhone(val) {
  if (!val) return null;
  let s = '';
  if (typeof val === 'object') {
    s = String(val.id || val.author || val.from || val.phone || val.number || val.wa_id || val.remoteJid || '');
  } else {
    s = String(val);
  }
  if (s.includes('@g.us') || s.includes('-')) return null;
  const digits = s.replace(/\D/g, '');
  return (digits.length >= 7 && digits.length <= 15) ? digits : null;
}

const sc = getPhone(item.author) || getPhone(item.from) || getPhone(item.sender) || getPhone(input.sender?.wa_id) || getPhone(input.contact) || "No disponible";
const sourceChatId = item.chat_id || item.chatId || input.source_chat_id || null;

return [{ json: {
  ...item,
  platform: "WhatsApp",
  sender_contact: sc,
  final_contact: sc,
  source_chat_id: sourceChatId,
  texto_limpio: String(textBody).trim(),
  looksValuable: String(textBody).length > 5
}}];

const results = [];
const HARD_BLOCK = new Set(["crypto", "binance", "casino", "usdt", "bitcoin", "wallet", "trading", "ganar dinero", "инди", "контент", "onlyfans", "вирт", "sugar baby", "sugar daddy", "anal", "masaje erotico", "ingles", "english"]);
const BANNED_PREFIXES = ["58", "57", "92", "91", "62"];

function norm(v) { return String(v || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""); }

for (const item of $input.all()) {
  const data = item.json;
  const text = norm(data.texto_limpio);
  const sender = String(data.final_contact).replace(/\D/g, "");

  let rejectReason = null;
  if (BANNED_PREFIXES.some(p => sender.startsWith(p))) rejectReason = "prefix_banned";
  else if (HARD_BLOCK.has(text)) rejectReason = "hard_block_match";

  results.push({ json: { ...data, looksValuable: !rejectReason, reject_reason: rejectReason } });
}
return results;

const results = [];
const store = $getWorkflowStaticData('global');
if (!store.history) store.history = [];

const now = Date.now();
const TTL = 86400000;
store.history = store.history.filter(h => now - h.time < TTL);

for (const item of $input.all()) {
  const fp = String(item.json.texto_limpio).substring(0, 100);
  if (!store.history.some(h => h.fp === fp)) {
    store.history.push({ time: now, fp });
    results.push(item);
  }
}
return results;

// PARSE JSON v5.8 (METADATA PRESERVE)
const input = $json;
const rawText = input.output || input.text || "";
const cleanText = rawText.replace(/```json|```/g, '').trim();

// RECUPERAR METADATA PERDIDA (prioridad absoluta a los nodos de extracción)
let metadataWA = {};
try { metadataWA = $node["Extract Metadata WA1"].json || {}; } catch (e) {}
let metadataTG = {};
try { metadataTG = $node["Extract Metadata TG1"].json || {}; } catch (e) {}

const platform = metadataWA.platform || metadataTG.platform || input.platform || "WhatsApp";
let contact = metadataWA.final_contact || metadataTG.final_contact || input.sender_contact || input.final_contact || "Desconocido";

// Si el contacto es un ID de grupo, lo marcamos como Desconocido
if (String(contact).includes('@g.us') || String(contact).length > 20) { contact = "Desconocido"; } else if (/^\d{7,15}$/.test(String(contact))) { contact = '+' + contact; } 

let parsed = {};
try {
  if (cleanText) parsed = JSON.parse(cleanText);
} catch (e) {
  const catMatch = cleanText.match(/"category"\s*:\s*"(.*?)"/i);
  if (catMatch) parsed.category = catMatch[1];
}

const lowerRaw = (input.texto_limpio || metadataWA.texto_limpio || metadataTG.texto_limpio || "").toLowerCase();
const isJobish = lowerRaw.includes("busco") || lowerRaw.includes("disponible") || lowerRaw.length > 20;

const finalData = {
  platform,
  contact,
  source_chat_id: metadataWA.source_chat_id || metadataTG.source_chat_id || input.source_chat_id || "0",
  city: parsed.city || "Global",
  budget: parsed.budget || "Negociable",
  category: (parsed.category || (isJobish ? "evento" : "trash")).toLowerCase(),
  text_es: parsed.text_es || input.texto_limpio || lowerRaw || "Sin descripción",
  title_es: parsed.title_es || (lowerRaw ? lowerRaw.substring(0, 40) : "Nuevo Lead"),
  trash: parsed.trash === true || (parsed.category === 'trash' && !isJobish) || false
};

const highValueKeywords = ["mansour", "ibiza", "lio", "pacha", "monaco", "viena", "dubai", "manila"];
if (highValueKeywords.some(kw => lowerRaw.includes(kw))) {
  finalData.trash = false;
  if (finalData.category === 'trash') finalData.category = "evento";
}

return [{ json: finalData }];

const results = [];
const text = $json.texto_limpio || '';
const linkRegex = /chat\.whatsapp\.com\/[a-zA-Z0-9]{20,26}/g;
const matches = text.match(linkRegex);

if (matches) {
  for (const match of matches) {
    results.push({ json: { link: 'https://' + match, platform: $json.platform, source: $json.source_chat_id } });
  }
}
return results;
